var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"아르카데나 제국. 남부 대륙 산악 마을 <color=#ffd34c>몬테</color>.","JPN":"アルカデナ帝国。南部大陸山岳の村、<color=#ffd34c>モンテ</color>。","ENG":"The Empire of Arcadena. <color=#ffd34c>Monte</color>, a mountain village in the southern continent.","TWN":"艾爾卡特納帝國南部山區村莊<color=#ffd34c>蒙特</color>"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"subtitle","speaker":null,"text":{"KOREA":"구원기사단. 출정 <color=#ffd34c>하루 전</color>.","JPN":"救世騎士団。出征<color=#ffd34c>1日前</color>。","ENG":"Knights of Redemption. <color=#ffd34c>One day before</color> departure.","TWN":"救贖騎士團出征<color=#ffd34c>前一天</color>"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"전하. 갑작스럽지만 괜찮으시겠습니까?","JPN":"殿下。急遽お耳に入れたいことが。よろしいでしょうか。","ENG":"Your Highness, may I have a moment to talk to you?","TWN":"殿下，方便跟殿下說句話嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그래. 무슨 일인가, 알렌 경.","JPN":"ああ。どうした、バーミンガム卿。","ENG":"You may. What is it, Sir Allen?","TWN":"說吧，艾倫卿，什麼事？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"몬테에 출정을 떠났던 선발대의 연락이 끊겼습니다.","JPN":"モンテへ出征した先発隊からの連絡が途切れました。","ENG":"We lost contact with the advance party that left for Monte.","TWN":"我們與率先出征到蒙特的先遣隊失去聯繫。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"산 정상에 있는 마을이니 물자 공급의 어려움도 있겠지만, 괴수의 규모 역시 저희 예상을 상회하는 것 같습니다.","JPN":"山の頂上にある村なので物資の供給が困難なこともありますが、怪獣の規模もまた我々の予想を上回るものと思われます。","ENG":"The village is on the top of a mountain, which makes it difficult to receive supplies, but the mass of the monsters seems to be greater than expected.","TWN":"由於村莊在山頂上，物資供給有一定的難度，但怪獸的規模似乎也超過我們的預期。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"과연, 사방이 숲인만큼 평범한 군대로는 버티는 것조차 쉽지 않은가.","JPN":"なるほど、四方が森である分、普通の軍隊では踏ん張るのにも難ありか。","ENG":"Even holding out seems tough for an ordinary army surrounded by forests.","TWN":"四周都是森林，普通的軍隊還是很難撐下去嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"현재 가용 가능한 병력의 수는 어떻지?","JPN":"現在、使える兵力の数は？","ENG":"What's the number of soldiers that can participate in battle now?","TWN":"我們現在可動員的兵力有多少？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"잇따른 전투로 부상을 입은 병사가 대부분입니다.","JPN":"相続く戦闘でほとんどの兵士が負傷しています。","ENG":"Most are injured from recurring combat.","TWN":"接二連三的戰爭導致兵力多有負傷。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"고된 행군이 예상되는 만큼, 실질적으로 가용 가능한 수는 적겠군요.","JPN":"厳しい行軍が予想されますので、実質的に使える兵力数は少ないでしょう。","ENG":"An arduous march is ahead of us, which means there will be fewer soldiers that will be available.","TWN":"考慮到這趟征途不易，可動員的兵力可能相當有限。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"연회도 앞두고 있으니 말이야. 이런 시기에 사상자가 늘었다간 사기 또한 누그러질 거다.","JPN":"宴も控えているからな。このような時期に死傷者が増えると士気も下がる。","ENG":"Not to mention the banquet will be held soon. It will be bad for morale if we lose more people at a time like this.","TWN":"慶功宴在即，若是此時再增加死傷人數，恐怕會影響士氣。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"움직인다면 소수 정예. 인가….","JPN":"動くなら少数精鋭、か……","ENG":"So we need a few good men to advance...","TWN":"還是派少數精銳…"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"알렌. 루크레시아와 샬롯을 부르도록. 몬테에는 평민을 포함한 네 명이서 움직인다.","JPN":"アレン。ルクレシアとシャーロットを呼べ。モンテには平民を含めた4人で動く。","ENG":"Allen. Call for Lucrecia and Carlota. I'll take them and the peasant to go forth.","TWN":"艾倫，把露可蕾西亞和夏洛特叫來。再加上我和平民，就我們四個去蒙特。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_01"},{"id":"L26_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"내가 없는 동안의 지휘권은 경에게 맡기지.","JPN":"私がいない間、指揮権は卿に任せよう。","ENG":"I'll leave you in charge while I am absent.","TWN":"我不在的時候，指揮權就交給你。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"전하께서 직접 움직이실 필요는 없습니다.","JPN":"殿下が自ら動かれるまでもございません。","ENG":"There is no need for you to go yourself, Your Highness.","TWN":"殿下無須親自前往。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L28_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"제게 일러두신다면 병력을 이끌고 가 처리하겠습니다.","JPN":"私にご指示くだされば、兵力を率いて処理して参ります。","ENG":"Give the orders, and I shall take some soldiers to take care of the matter.","TWN":"只要殿下一聲令下，我就立刻帶兵前往。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"무릇 군주라면 모범을 보여야지 않겠나. 제국의 황태자가 병사들만 움직일 수는 없지.","JPN":"君主たるもの、手本を見せるべきではないか。帝国の皇太子が兵士だけに頼るわけにもいくまい。","ENG":"A ruler must set an example for his subjects. As the crown prince of the Empire, I cannot sit idle while the soldiers offer their lives to our cause.","TWN":"身為一國之君理當以身作則。帝國的皇太子怎麼可以光是使喚士兵們，自己卻躲在安樂窩裡呢？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"연회까지 시간도 없으니, 가능한 한 신속하게 처리하고 오겠네.","JPN":"宴まで時間もない、できるだけ速やかに処理して来よう。","ENG":"We do not have much time until the banquet, so I shall make haste.","TWN":"距離慶功宴沒剩多少時間，我會盡速處理完畢回來。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"…그래서.","JPN":"……で。","ENG":"...So.","TWN":"意思是…"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"고작 넷이서 움직인다는 겁니까? 선발대가 전멸했을지도 모르는 위험한 장소를?","JPN":"たった4人で動くということですか？　先発隊が全滅したかもしれない、危険な場所で？","ENG":"You wish to enter a perilous area, where the advance party might have been wiped out, with just four people?","TWN":"就我們四個人嗎？目的地是先遣隊或許已經全軍覆沒的危險地方？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"허세가 심하시군요, 전하.","JPN":"虚勢を張るにも程度というものがあります、殿下。","ENG":"Very self-assured, Your Highness.","TWN":"殿下會不會太不知輕重？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"괴수와의 싸움을 넘어 부상당한 주민들까지 보살피기엔 저희만으로는 부족합니다.","JPN":"怪獣との戦いだけでなく怪我をした住民まで看るには、この人数では足りません。","ENG":"We won't be enough to fight the monsters, much less take care of the injured villagers.","TWN":"還要照顧那些和怪獸戰鬥時受傷的百姓，光靠我們四個是不夠的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"굳이 다른 병력들을 내버려 두고 움직일 필요는 없습니다.","JPN":"他の兵力を差し置いて、あえて私たちが動く必要はないように思います。","ENG":"There is no need for us to move when there are other soldiers available.","TWN":"有需要放著其他的兵力不用，四個人硬上嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"노예 출신 아니랄까 봐 패전부터 상정하고 보는군.","JPN":"さすがは奴隷出身だ。敗戦から想定するのだな。","ENG":"Your assumption of our loss makes it clear you're a former slave.","TWN":"果然是出身卑微之人，都還沒打，就已經認定會戰敗。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"영리하지 못한 건 핏줄 탓이겠으니 뭐라 나무라지는 않으마.","JPN":"賢くないのは血のせいであろうから、あえて言うまい。","ENG":"I shall not fault you for your ignorance, as it is in your blood.","TWN":"會有這種想法只能怪你的出身，我不會怪你的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"전하께서 나서실 필요도 없습니다. 저와 구원자면 충분합니다.","JPN":"殿下がお出になるまでもありません。私と救世主だけで十分です。","ENG":"You need not lift a finger for this matter to be handled, Your Highness. The Savior and I should suffice.","TWN":"無需勞煩殿下，只要有我和救贖者大人便已足夠。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L46_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"샬롯 님이야 어련하시겠죠. 전 객기가 아닌 현실을 말씀드리는 겁니다.","JPN":"シャーロット様はそうでしょう。私は一時の感情論ではなく、現実を語っているのです。","ENG":"I am sure that might be fine for you, Carlota. But I'm just being realistic.","TWN":"夏洛特說的沒錯。但我不是意氣用事，而是陳述事實。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"굳이 불필요한 위험을 감수할 필요는 없습니다.","JPN":"冒す必要のない危険にあえて身を投じる必要はありません。","ENG":"There is no need to take any unnecessary risks.","TWN":"何必要以身犯險。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"……있지, 루크레시아.","JPN":"……ねえ、ルクレシア。","ENG":"…Well, Lucrecia.","TWN":"……露可蕾西亞。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"추측일 뿐이지만, 다른 분들은 아직 살아있을 거라 생각해.","JPN":"ただの憶測だけど、他の人たちはまだ生きてると思うんだ。","ENG":"It's just my assumption, but I think the others are still alive.","TWN":"雖然這只是我個人的猜測，但我想應該還有倖存者。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"다른 분들이… 살아 계신다고요? 하지만.","JPN":"他の人たちが……まだ生きている？　ですが。","ENG":"The others... are alive? But.","TWN":"你說…還有倖存者？就算如此…"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하하! 알렌 경만큼은 아니지만 제복이 어울리는 정도는 된 것 같군.","JPN":"ハハ！　バーミンガム卿ほどではないが、礼装に見合う程度にはなったようだな。","ENG":"Ha ha! It seems like you're growing into your uniform, even though you're far from living up to Sir Allen's reputation.","TWN":"哈哈！雖然你還不如艾倫卿，但總算是有穿上那套制服的資格。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그럼 이쯤에서 문제다.","JPN":"では、ここで問題だ。","ENG":"Now, let me ask you a question.","TWN":"那麼問題來了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"맹수를 노리는 가장 쉬운 방법이 뭐라고 생각하지?","JPN":"猛獣を仕留めるもっとも簡単な方法は何だと思う？","ENG":"What do you think is the easiest method to lure a beast?","TWN":"對付猛獸最簡單的方法是什麼？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"죽은… 척하기?","JPN":"死んだ……ふり？","ENG":"Play... dead?","TWN":"是…裝死？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"저도 아닌 거 아니까 그런 식으로 쳐다보지 마세요.","JPN":"私も不正解だということはわかっていますから、そんな目で見ないでください。","ENG":"Stop looking at me like that. I know that's not the answer.","TWN":"我當然知道不是，說說而已，不用那樣看我。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"정답은 맹수가 스스로를 포식자인양 착각에 빠트리는 거다.","JPN":"正解は、猛獣に自分が捕食者であると勘違いさせることだ。","ENG":"The correct answer is, tricking the beast into thinking that it's a predator.","TWN":"答案是讓猛獸誤以為自己是掠食者。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"먹이에 취한 맹수만큼, 심장을 노리기 쉬운 적은 없는 법이니까.","JPN":"エサに夢中になっている猛獣ほど、心臓を狙いやすい敵はいないからな。","ENG":"There's no easier prey than a beast that's fixating on its food.","TWN":"因為沉醉於獵物的猛獸是最容易狙擊的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"먹이에 취하다니… 설마 괴수들을 마을 쪽으로 유인하실 생각입니까?","JPN":"エサに夢中になるって……まさか、怪獣たちを村の方へにおびき寄せるつもりですか？","ENG":"Fixated on its food...? Do you mean to lure the monsters toward the village?","TWN":"沉醉於獵物…難道殿下是想把怪獸引誘到村莊那邊去嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L21_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"굳이 아니더라도 자연스럽게 모일 테지.","JPN":"あえてそうしなくても自然に集まる。","ENG":"They will be gathering there without our intervention.","TWN":"就算我不刻意把它們引到村莊，它們也會自然地聚集過來的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"연락책이 마을에서 나오지 못할 정도로 난감한 상황이지만 말이다.","JPN":"問題は、連絡役が村から出られないほどだということだな。","ENG":"Alas, our allies are in a dire situation where they are unable to leave the village.","TWN":"問題在於，在外面的人要如何得知村裡的情況。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그래서 소수로 움직이신다는 거네요.","JPN":"それで少数で動くというわけですね。","ENG":"Which is why you want a small group.","TWN":"所以殿下才打算只帶著少數人行動。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"대군을 끌고 간다면, 낌새를 눈치챈 괴수들이 달아날 테니까요.","JPN":"大勢で行くと、何かを感じ取った怪獣たちが逃げるはずですから。","ENG":"Because a big army would alert the monsters and make them flee.","TWN":"如果帶著大隊人馬過去，怪獸察覺到動靜就會逃跑。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그래. 이런 넓은 산악 지역에서 일일이 괴수를 찾아다닐 필요도 없겠지.","JPN":"そのとおりだ。このような広い山岳地域で、いちいち怪獣を探し回る必要もない。","ENG":"Indeed. It would save us the trouble of finding all the monsters in the expansive mountain areas.","TWN":"沒錯，沒必要在寬闊的山區裡四處尋找怪獸。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"작전은 간단하다.","JPN":"作戦は簡単だ。","ENG":"The plan is simple.","TWN":"作戰方法很簡單。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"네 명이 각각의 위치에서 화력을 집중. 마을에 갇힌 선발대의 길을 뚫는다.","JPN":"4人が各自の位置で火力を集中。村に閉じこめられた先発隊に道を開く。","ENG":"We four will focus fire from four different directions and make a way for the advance party to escape the village.","TWN":"四人在各自的崗位上集中火力，為困在村裡先遣隊開路。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그리고 각 방향에서 병력이 빠져나오면 그들과 협력해 포위망을 형성.","JPN":"そして、各方面から兵力が脱出できたら、彼らと協力し包囲網を形成。","ENG":"When the soldiers make it out, we combine forces with them to surround the monsters.","TWN":"等兵力從四方撤出後，再會合包圍住怪獸。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"제국군과 함께 괴수들을 일제히 섬멸한다.","JPN":"帝国軍と共に怪獣たちを一斉殲滅する。","ENG":"From there on, we eliminate all the monsters together.","TWN":"和帝國軍一起合力徹底殲滅怪獸。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L39_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"작전 자체는 간단합니다만. 선발대가 전멸했을 가능성도 배제할 수는 없습니다.","JPN":"作戦自体は簡単ですが。先発隊が全滅している可能性もないとは言えません。","ENG":"The plan itself is simple, but there is still the underlying possibility that the advance party has been decimated.","TWN":"作戰方法本身很簡單，但不能排除先遣隊已經全軍覆沒的可能性。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"선발대가 당했다면 살아남은 주민은 없겠지.","JPN":"先発隊がやられているなら、生き残った住民はいないだろう。","ENG":"If the advance party was decimated, no villager would have survived afterward.","TWN":"先遣隊全軍覆沒的話，居民也不可能活下來。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그 시점에서 이번 원정의 의미도 사라진다는 소리다.","JPN":"その時点でこの遠征の意味もなくなるということだ。","ENG":"Which would also invalidate the purpose of this expedition.","TWN":"這也就表示，已經沒有遠征的必要性。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"이해했습니다. 작전은 지금 바로 시작하면 될까요?","JPN":"理解しました。作戦は、今すぐ始めればいいですか？","ENG":"Understood. Should we start right away?","TWN":"明白，那現在就開始進行作戰嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"빠르면 빠를수록 좋겠지. 언제까지 괴수 놈들이 날뛰게 둘 수는 없으니까.","JPN":"早ければ早いほど良い。いつまでも怪獣どもに好き勝手させておくわけにはいかないからな。","ENG":"The sooner, the better. We cannot have those monsters run amok forever.","TWN":"當然是越快越好，不能放任那些怪獸繼續作亂。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"자아, 주제 파악도 못하는 괴물들에게 이 땅의 진정한 주인이 누구인지 알려줄 때다!","JPN":"さあ、身の程知らずの怪獣どもに、この地の真の主が誰なのかをわからせてやるのだ！","ENG":"Now then, it is time we show those insolent monsters whose territory they are causing trouble on!","TWN":"好！我們要告訴那些怪物，這塊土地的堂主是誰！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L2_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"구원의 깃발 아래 그대들의 긍지를 드높이도록.","JPN":"救援の旗の下に、諸君の誇りを掲げよ。","ENG":"Stand proud beneath the flag of redemption.","TWN":"在救贖的旗幟下展現你們的驕傲吧！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"구원 기사단. 진군하라!","JPN":"救世騎士団。進軍！","ENG":"Knights of Redemption, march forward!","TWN":"救贖騎士團，出征！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};